def student_average(grades, student_idx):
    row = grades[student_idx]
    if not row:
        return 0
    return sum(row) / len(row)

def assignment_average(grades, col):
    total = sum(grades[r][col] for r in range(len(grades)))
    return total / len(grades)

def find_failing(grades, threshold=70):
    failing = []
    for r in range(len(grades)):
        for c in range(len(grades[r])):
            if grades[r][c] < threshold:
                failing.append((r, c))
    return failing

